B.XY=new A.bR([3,"\u80fd\u591f\u8ddf\u4e0a\u573a\u4e0a\u7684\u8282\u594f\uff0c\u6709\u57fa\u672c\u7684\u901f\u5ea6\u548c\u8df3\u8dc3\u80fd\u529b",5,"\u5728\u8dd1\u52a8\u548c\u8d77\u8df3\u65f6\u8868\u73b0\u7a33\u5b9a\uff0c\u901f\u5ea6\u4e2d\u7b49\u504f\u4e0a",7,"\u62e5\u6709\u51fa\u8272\u7684\u7206\u53d1\u529b\uff0c\u80fd\u5728\u5173\u952e\u65f6\u523b\u5c55\u73b0\u901f\u5ea6\u4f18\u52bf",10,"\u573a\u4e0a\u6700\u5feb\u7684\u9009\u624b\u4e4b\u4e00\uff0c\u8df3\u8dc3\u548c\u51b2\u523a\u80fd\u529b\u9876\u5c16"],t.TM)
